// src/playground.ts
var esbuildReady = null;
function initEsbuild() {
  if (!esbuildReady) {
    esbuildReady = esbuildWasm.initialize({
      wasmURL: "esbuild.wasm"
    });
  }
  return esbuildReady;
}
var Playground = class {
  selectorEl;
  editorEl;
  terminalEl;
  statusEl;
  editor = null;
  terminal = null;
  fitAddon = null;
  webcontainer = null;
  shellWriter = null;
  selectedIndex = -1;
  debounceTimer = null;
  isReady = false;
  constructor(selectorEl, editorEl, terminalEl, statusEl) {
    this.selectorEl = selectorEl;
    this.editorEl = editorEl;
    this.terminalEl = terminalEl;
    this.statusEl = statusEl;
  }
  async init() {
    this.buildSelector();
    this.initEditor();
    this.initTerminal();
    this.selectDemo(0, false);
    await this.bootWebContainer();
  }
  buildSelector() {
    const ul = document.createElement("ul");
    ul.className = "demo-list";
    for (let i = 0; i < demos.length; i++) {
      const demo = demos[i];
      const li = document.createElement("li");
      li.className = "demo-item";
      li.dataset.idx = String(i);
      li.innerHTML = `<span class="demo-title">${demo.title}</span><span class="demo-desc">${demo.description}</span>`;
      li.addEventListener("click", () => this.selectDemo(i, true));
      ul.appendChild(li);
    }
    this.selectorEl.appendChild(ul);
  }
  initEditor() {
    const updateListener2 = EditorView.updateListener.of((update) => {
      if (update.docChanged) {
        this.onCodeChange();
      }
    });
    this.editor = new EditorView({
      state: EditorState.create({
        doc: "",
        extensions: [
          basicSetup,
          javascript({ jsx: true, typescript: true }),
          oneDark,
          updateListener2,
          EditorView.lineWrapping,
          EditorView.theme({
            "&": { height: "100%", fontSize: "13px" },
            ".cm-scroller": { overflow: "auto" },
            ".cm-content": { fontFamily: "'JetBrains Mono', 'Fira Code', 'SF Mono', monospace" },
            ".cm-gutters": { fontFamily: "'JetBrains Mono', 'Fira Code', 'SF Mono', monospace" }
          })
        ]
      }),
      parent: this.editorEl
    });
  }
  initTerminal() {
    this.terminal = new import_xterm.Terminal({
      cursorBlink: true,
      cursorStyle: "bar",
      fontFamily: "'JetBrains Mono', 'Fira Code', 'SF Mono', 'Cascadia Code', Consolas, monospace",
      fontSize: 13,
      lineHeight: 1.2,
      theme: {
        background: "#0d1117",
        foreground: "#c9d1d9",
        cursor: "#c9d1d9",
        cursorAccent: "#0d1117",
        selectionBackground: "#264f78",
        black: "#484f58",
        red: "#ff7b72",
        green: "#3fb950",
        yellow: "#d29922",
        blue: "#58a6ff",
        magenta: "#bc8cff",
        cyan: "#39c5cf",
        white: "#c9d1d9",
        brightBlack: "#6e7681",
        brightRed: "#ffa198",
        brightGreen: "#56d364",
        brightYellow: "#e3b341",
        brightBlue: "#79c0ff",
        brightMagenta: "#d2a8ff",
        brightCyan: "#56d4dd",
        brightWhite: "#f0f6fc"
      }
    });
    this.fitAddon = new import_addon_fit.FitAddon();
    this.terminal.loadAddon(this.fitAddon);
    this.terminal.open(this.terminalEl);
    this.fitAddon.fit();
    const resizeObserver = new ResizeObserver(() => {
      this.fitAddon?.fit();
    });
    resizeObserver.observe(this.terminalEl);
    this.terminal.writeln("\x1B[1;36mrich-js-ink playground\x1B[0m");
    this.terminal.writeln("\x1B[2mBooting WebContainer...\x1B[0m");
  }
  setStatus(msg) {
    this.statusEl.textContent = msg;
  }
  async bootWebContainer() {
    try {
      this.setStatus("Fetching prebuilt environment...");
      this.terminal?.writeln("\x1B[2mFetching prebuilt environment + booting...\x1B[0m");
      const [snapshotBuf, wc] = await Promise.all([
        fetch("prebuild.bin").then((r) => {
          if (!r.ok) throw new Error(`Failed to fetch prebuild.bin: ${r.status}`);
          return r.arrayBuffer();
        }),
        WebContainer.boot()
      ]);
      this.webcontainer = wc;
      this.setStatus("Mounting prebuilt environment...");
      this.terminal?.writeln("\x1B[2mMounting prebuilt node_modules + demos...\x1B[0m");
      await this.webcontainer.mount(snapshotBuf);
      this.terminal?.writeln("\r\n\x1B[1;32mReady!\x1B[0m Run demos with: \x1B[1mnode demo.js\x1B[0m\r\n");
      await this.startShell();
      this.isReady = true;
      this.setStatus("Ready \u2014 select a demo and press Run");
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      this.terminal?.writeln(`\r
\x1B[1;31mError: ${msg}\x1B[0m`);
      this.setStatus(`Error: ${msg}`);
    }
  }
  async startShell() {
    const shellProcess = await this.webcontainer.spawn("jsh", {
      terminal: {
        cols: this.terminal.cols,
        rows: this.terminal.rows
      }
    });
    shellProcess.output.pipeTo(
      new WritableStream({
        write: (data) => {
          this.terminal?.write(data);
        }
      })
    );
    const input = shellProcess.input.getWriter();
    this.shellWriter = input;
    this.terminal.onData((data) => {
      input.write(data);
    });
    this.terminal.onResize(({ cols, rows }) => {
      shellProcess.resize({ cols, rows });
    });
  }
  selectDemo(index, run) {
    const demo = demos[index];
    if (!demo) return;
    const items = this.selectorEl.querySelectorAll(".demo-item");
    items.forEach((el, i) => {
      el.classList.toggle("active", i === index);
    });
    this.selectedIndex = index;
    if (this.editor) {
      this.editor.dispatch({
        changes: {
          from: 0,
          to: this.editor.state.doc.length,
          insert: demo.code
        }
      });
    }
    if (run && this.isReady) {
      this.runCurrentDemo();
    }
    this.terminal?.focus();
  }
  onCodeChange() {
    if (this.debounceTimer) clearTimeout(this.debounceTimer);
    this.debounceTimer = setTimeout(() => {
      this.writeDemoFile();
    }, 500);
  }
  async writeDemoFile() {
    if (!this.webcontainer || !this.editor) return;
    const code = this.editor.state.doc.toString();
    const demo = demos[this.selectedIndex];
    if (!demo) return;
    const isComponentDef = /^(?:function|const|let|var)\s/.test(code.trim()) || code.trim().startsWith("return ");
    const imports = `import React, { useState, useEffect, useCallback, useRef } from "react";
import { render, Box, Text, useInput } from "ink";
import {
  RichPanel, RichTable, RichTree, RichMarkup, RichRule,
  RichSyntax, RichMarkdown, RichJSON, RichPretty, RichColumns,
  RichTraceback, RichSpinner, RichProgressBar, RichStatus,
  RichProgress, RichPrompt, RichConfirm, RichSelect,
  RichThemeProvider, useProgress, useSpinnerFrame, useRichRenderable,
  renderToString, Style, RichText, renderMarkup, ColorSystem,
  SPINNERS, DEFAULT_SPINNER,
  ROUNDED, DOUBLE, HEAVY, ASCII, SQUARE, MINIMAL, MARKDOWN, HORIZONTALS, SIMPLE, ASCII2,
} from "rich-js-ink";
`;
    const jsxSource = isComponentDef ? `${imports}
const Component = (() => { ${code} })();
render(React.createElement(RichThemeProvider, null, React.createElement(Component)));
` : `${imports}
function App() {
  return (
    <RichThemeProvider>
      ${code}
    </RichThemeProvider>
  );
}
render(React.createElement(App));
`;
    await initEsbuild();
    const result = await esbuildWasm.transform(jsxSource, {
      loader: "tsx",
      jsx: "automatic",
      jsxImportSource: "react",
      target: "esnext",
      format: "esm"
    });
    await this.webcontainer.fs.writeFile("demo.js", result.code);
  }
  async runCurrentDemo() {
    try {
      await this.writeDemoFile();
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      this.terminal?.writeln(`\r
\x1B[1;31mCompile error: ${msg}\x1B[0m`);
      return;
    }
    if (this.shellWriter) {
      this.shellWriter.write("");
      await new Promise((r) => setTimeout(r, 100));
      this.shellWriter.write("node demo.js\n");
    }
  }
  destroy() {
    this.editor?.destroy();
    this.terminal?.dispose();
    this.webcontainer?.teardown();
  }
};

// src/main.ts
var app = document.getElementById("app");
app.innerHTML = `
  <header>
    <h1>rich-js-ink</h1>
    <p class="tagline">Rich terminal renderables as declarative React components for Ink</p>
    <p class="tagline-sub">Live playground with a real Node.js terminal \u2014 edit code, click Run, interact</p>
  </header>
  <div class="playground">
    <div class="col col-selector" id="selector">
      <div class="col-header">Components</div>
    </div>
    <div class="col col-editor" id="editor-col">
      <div class="col-header">JSX Editor</div>
      <div id="editor-mount"></div>
      <div class="editor-actions">
        <button id="run-btn" class="run-btn" disabled>Run</button>
        <span id="status" class="status">Booting...</span>
      </div>
    </div>
    <div class="col col-terminal" id="terminal-col">
      <div class="col-header">Terminal</div>
      <div id="terminal-mount"></div>
    </div>
  </div>
  <footer>
    <a href="https://github.com/brandon-fryslie/rich-js-ink">GitHub</a>
    \xB7
    <a href="https://github.com/brandon-fryslie/rich-js">rich-js</a>
    \xB7
    <a href="https://github.com/vadimdemedes/ink">Ink</a>
    \xB7
    Powered by <a href="https://webcontainers.io">WebContainers</a>
  </footer>
`;
var runBtn = document.getElementById("run-btn");
var playground = new Playground(
  document.getElementById("selector"),
  document.getElementById("editor-mount"),
  document.getElementById("terminal-mount"),
  document.getElementById("status")
);
runBtn.addEventListener("click", () => {
  playground.runCurrentDemo();
});
playground.init().then(() => {
  runBtn.disabled = false;
});
